const app = express();
const parser = new xml2js.Parser();

app.use(express.json());
app.use(express.urlencoded({ extended: false }));

app.post('/upload', (req, res) => {
  const form = new formidable.IncomingForm();

  form.parse(req, async (err, fields, files) => {
    if (err) return res.status(500).send({ error: err });

    const xmlData = fs.readFileSync(files.xmlFile.path, 'utf8');
    await parser.parseString(xmlData, async (err, result) => {
      if (err) return res.status(500).send({ error: err });

      // Extract configuration settings from the parsed XML into a JavaScript object.
      const config = extractConfig(result);

      res.json(config);
    });
  });
});

